import 'dotenv/config';
import Inconvo from '@inconvoai/node';
import { inconvoDataAgent } from '@inconvoai/vercel-ai-sdk';
import { generateText } from 'ai';
import { openai } from '@ai-sdk/openai';
import fs from 'fs';
import path from 'path';
import { fileURLToPath } from 'url';

const __dirname = path.dirname(fileURLToPath(import.meta.url));

async function main() {
  const inconvo = new Inconvo({
    apiKey: process.env.INCONVO_API_KEY,
    // Note: The Inconvo client might use different property names for options
    // based on common patterns, but I'll stick to what was requested if possible.
    // However, looking at the d.ts, it seems it uses ClientOptions.
  });

  const tools = inconvoDataAgent({
    inconvo,
    agentId: process.env.INCONVO_AGENT_ID,
  });

  const { text } = await generateText({
    model: openai('gpt-4o'),
    tools,
    prompt: 'What is the total amount of orders?',
    maxSteps: 10,
  });

  const responseObj = { response: text };
  fs.writeFileSync(
    path.join(__dirname, 'response.json'),
    JSON.stringify(responseObj, null, 2)
  );

  console.log(text);
}

main().catch(console.error);

