import 'dotenv/config';
import Inconvo from '@inconvoai/node';
import { inconvoDataAgent } from '@inconvoai/vercel-ai-sdk';
import { generateText } from 'ai';
import { openai } from '@ai-sdk/openai';
import fs from 'fs';
import path from 'path';
import { fileURLToPath } from 'url';

const __dirname = path.dirname(fileURLToPath(import.meta.url));

async function main() {
  console.log('Starting agent...');
  const inconvo = new Inconvo({
    apiKey: process.env.INCONVO_API_KEY,
  });

  const tools = inconvoDataAgent({
    inconvo,
    agentId: process.env.INCONVO_AGENT_ID,
    userIdentifier: 'agent-user',
    userContext: {
      dbUrl: process.env.INCONVO_DB_URL,
    },
  });

  console.log('Calling generateText...');
  const result = await generateText({
    model: openai('gpt-4o'),
    tools,
    prompt: 'What is the total amount of orders?',
    maxSteps: 10,
    onStepFinish: (step) => {
      console.log('Step finished:', JSON.stringify(step, null, 2));
    }
  });

  console.log('Final text:', result.text);

  const responseObj = { response: result.text };
  fs.writeFileSync(
    path.join(__dirname, 'response.json'),
    JSON.stringify(responseObj, null, 2)
  );

  console.log('Done.');
}

main().catch((err) => {
  console.error('Error in main:', err);
  process.exit(1);
});

