import { generateText } from 'ai';
import { openai } from '@ai-sdk/openai';
import fs from 'fs';
import path from 'path';
import { fileURLToPath } from 'url';

const __dirname = path.dirname(fileURLToPath(import.meta.url));

async function main() {
  console.log('Starting agent...');
  const inconvo = new Inconvo({
    apiKey: process.env.INCONVO_API_KEY,
  });

  const tools = inconvoDataAgent({
    inconvo,
    agentId: process.env.INCONVO_AGENT_ID,
    userIdentifier: 'agent-user',
    // removed userContext because it is disabled for this agent
  });

  console.log('Calling generateText...');
  const result = await generateText({
    model: openai('gpt-4o'),
    tools,
    prompt: 'What is the total amount of orders?',
    maxSteps: 10,
    system: 'You are a data analyst assistant. Use the provided tools to answer questions. Start by getting the data summary, then start a conversation, and then message the agent.',
  });

  console.log('Final text:', result.text);

  const responseObj = { response: result.text };
  fs.writeFileSync(
    path.join(__dirname, 'response.json'),
