// src/tools/inconvo.ts
import Inconvo from "@inconvoai/node";
import { tool } from "ai";
import { z } from "zod";

// src/tools/constants.ts
var defaultMessageDataAgentDescription = [
  "You are the orchestrator, not the analyst.",
  "Translate the user's request into a short, precise data question for the analyst.",
  "Keep one goal; include key constraints like time range, top/bottom N, and sort.",
  "Do not guess schema, fields, grain, or filters.",
  "Do not prescribe formulas or how to calculate metrics; let the analyst decide.",
  "If the user explicitly defines a metric, you may keep the metric name but drop the formula.",
  "Do not bundle multiple sub-questions or add formatting requirements.",
  "If the request is unclear, ask one clarifying question instead of making assumptions.",
  "You can use the 'get{name}DataAgentConnectedDataSummary' tool before the first question to learn what data is available.",
  "Do not repeat information already provided by the analyst in your user message.",
  "Don't define any metrics or calculations yourself; the data agent is the source of truth.",
  "If there is a question about how something that came from the data analyst was calculated, ask the analyst directly."
].join("\n");

// src/tools/inconvo.ts
var ensureSerializer = (serialize) => {
  if (serialize) {
    return serialize;
  }
  return (value) => value;
};
var getDataAgentConnectedDataSummary = (options) => {
  const { inconvo: providedInconvo, agentId } = options;
  if (!agentId) {
    throw new Error(
      "getDataAgentConnectedDataSummary requires an agentId value."
    );
  }
  const inconvo = providedInconvo ?? new Inconvo();
  return tool({
    description: "Use this tool before you ask your first question. You will get a high level summary of the connected data. This can be used to get an overview of the data before asking more specific questions.",
    inputSchema: z.object({}),
    execute: async () => {
      const { dataSummary } = await inconvo.agents.dataSummary.retrieve(agentId);
      return dataSummary;
    }
  });
};
var startDataAgentConversation = (options) => {
  const {
    inconvo: providedInconvo,
    agentId,
    userIdentifier,
    userContext
  } = options;
  if (!agentId) {
    throw new Error("startDataAgentConversation requires an agentId value.");
  }
  if (!userIdentifier) {
    throw new Error(
      "startDataAgentConversation requires a userIdentifier value."
    );
  }
  if (!userContext) {
    throw new Error("startDataAgentConversation requires a userContext value.");
  }
  const inconvo = providedInconvo ?? new Inconvo();
  const resolveUserContext = async () => {
    const context = typeof userContext === "function" ? await userContext() : await Promise.resolve(userContext);
    if (!context || typeof context !== "object") {
      throw new Error("userContext must resolve to an object.");
    }
    return context;
  };
  return tool({
    description: "Begin a new conversation with the data analyst. Returns a new conversation ID which can be used with the 'messageDataAgent' tool. When messaging with the same conversation ID, the data analyst will remember the context of previous messages. You can start a new conversation at any time, even if you already have an active conversation.",
    inputSchema: z.object({}),
    execute: async () => {
      const context = await resolveUserContext();
      const conversation = await inconvo.agents.conversations.create(agentId, {
        userIdentifier,
        userContext: context
      });
      if (!conversation?.id) {
        return "Failed to start conversation with data analyst.";
      }
      return { conversationId: conversation.id };
    }
  });
};
var messageDataAgent = (options) => {
  const {
    inconvo: providedInconvo,
    agentId,
    messageDescription,
    stringifyResponse
  } = options;
  if (!agentId) {
    throw new Error("messageDataAgent requires an agentId value.");
  }
  const inconvo = providedInconvo ?? new Inconvo();
  const serialize = ensureSerializer(stringifyResponse);
  const analystDescription = messageDescription ?? defaultMessageDataAgentDescription;
  return tool({
    description: analystDescription,
    inputSchema: z.object({
      conversationId: z.string().describe("The ID of the conversation."),
      message: z.string().describe(
        "The user's analytics question, kept short and singular without added assumptions."
      )
    }),
    execute: async ({ conversationId, message }) => {
      const stream = inconvo.agents.conversations.response.create(
        conversationId,
        {
          agentId,
          message,
          stream: true
        }
      );
      let finalResponse = null;
      for await (const chunk of stream) {
        if (chunk.type === "response.completed") {
          finalResponse = chunk.response;
          break;
        }
      }
      if (!finalResponse) {
        throw new Error("No response received from Inconvo");
      }
      return serialize(finalResponse);
    }
  });
};
var inconvoDataAgent = (options) => {
